select u.* from base_user u
                    left join  base_group_member gm
                               on gm.user_id = u.id where gm.group_id = #{groupId}

select u.* from base_user u
                    left join  base_group_leader gm
                               on gm.user_id = u.id where gm.group_id = #{groupId}
